import SwiftUI
import UIKit

public struct NostrContentCallbacks: @unchecked Sendable {
    public var onMentionTap: (String) -> Void
    public var onHashtagTap: (String) -> Void
    public var onLinkTap: (URL) -> Void
    public var onImageTap: (URL) -> Void
    public var onEventRefTap: (String) -> Void

    public init(
        onMentionTap: @escaping (String) -> Void = { _ in },
        onHashtagTap: @escaping (String) -> Void = { _ in },
        onLinkTap: @escaping (URL) -> Void = { _ in },
        onImageTap: ((URL) -> Void)? = nil,
        onEventRefTap: @escaping (String) -> Void = { _ in }
    ) {
        self.onMentionTap = onMentionTap
        self.onHashtagTap = onHashtagTap
        self.onLinkTap = onLinkTap
        // `onImageTap` defaults to `onLinkTap` so apps that only wire the
        // generic link handler still get image-tap routing for free.
        self.onImageTap = onImageTap ?? onLinkTap
        self.onEventRefTap = onEventRefTap
    }
}

/// Shared image cache for the default `NostrContentRenderer.imageLoader`.
///
/// `AsyncImage` does not accept a `URLSession`, so its default behaviour
/// relies on whatever is configured on `URLCache.shared`. The default loader
/// in `NostrContentRenderer` therefore drives a dedicated `URLSession`
/// directly (downloading bytes and rendering via `Image(uiImage:)`) so the
/// 32 MB memory / 256 MB disk cache is actually used.
///
/// Apps wanting Kingfisher / Nuke / SDWebImage should replace
/// `NostrContentRenderer.imageLoader` rather than mutate this cache.
public enum NostrImageCache {
    public static let urlCache: URLCache = URLCache(
        memoryCapacity: 32 * 1024 * 1024,
        diskCapacity: 256 * 1024 * 1024,
        diskPath: "nmp-content-image-cache"
    )

    public static let session: URLSession = {
        let config = URLSessionConfiguration.default
        config.urlCache = urlCache
        config.requestCachePolicy = .returnCacheDataElseLoad
        return URLSession(configuration: config)
    }()
}

public struct NostrContentRenderer: @unchecked Sendable {
    public var textColor: Color
    public var secondaryTextColor: Color
    public var mentionColor: Color
    public var hashtagColor: Color
    public var linkColor: Color
    public var quoteBorderColor: Color
    public var quoteBackgroundColor: Color
    public var codeBackgroundColor: Color
    public var placeholderColor: Color
    public var callbacks: NostrContentCallbacks
    /// Image loader closure. Apps can swap this for a Kingfisher / Nuke /
    /// SDWebImage adapter without re-deriving the component surface. The
    /// default driver uses a dedicated `URLSession` over `NostrImageCache`
    /// (32 MB memory / 256 MB disk) so disk caching works out of the box.
    public var imageLoader: @Sendable (URL) -> AnyView
    /// Pre-resolved emoji shortcode → image map. Apps populate this from
    /// kind:0 / NIP-30 emoji tag data; an empty dict (the default) makes the
    /// content view fall back to literal `:shortcode:` text.
    public var emojiImages: [String: UIImage]

    public init(
        textColor: Color = .primary,
        secondaryTextColor: Color = .secondary,
        mentionColor: Color = .accentColor,
        hashtagColor: Color = .accentColor,
        linkColor: Color = .accentColor,
        quoteBorderColor: Color = Color.gray.opacity(0.35),
        quoteBackgroundColor: Color = Color.gray.opacity(0.08),
        codeBackgroundColor: Color = Color.gray.opacity(0.15),
        placeholderColor: Color = Color.gray.opacity(0.6),
        callbacks: NostrContentCallbacks = NostrContentCallbacks(),
        imageLoader: (@Sendable (URL) -> AnyView)? = nil,
        emojiImages: [String: UIImage] = [:]
    ) {
        self.textColor = textColor
        self.secondaryTextColor = secondaryTextColor
        self.mentionColor = mentionColor
        self.hashtagColor = hashtagColor
        self.linkColor = linkColor
        self.quoteBorderColor = quoteBorderColor
        self.quoteBackgroundColor = quoteBackgroundColor
        self.codeBackgroundColor = codeBackgroundColor
        self.placeholderColor = placeholderColor
        self.callbacks = callbacks
        self.imageLoader = imageLoader ?? Self.defaultImageLoader
        self.emojiImages = emojiImages
    }

    /// Default loader: drives `NostrImageCache.session` directly (so disk
    /// caching is real, not just memory). Shows `ProgressView()` while
    /// loading, a gray placeholder on failure, `scaledToFill()` on success.
    @Sendable
    public static func defaultImageLoader(_ url: URL) -> AnyView {
        AnyView(NostrDefaultImageView(url: url))
    }
}

/// Default loader view backing `NostrContentRenderer.defaultImageLoader`.
/// Pulled out as a concrete `View` so the loader closure stays
/// `@Sendable`-clean and the cache-driving network call is testable.
private struct NostrDefaultImageView: View {
    let url: URL
    @State private var image: UIImage?
    @State private var didFail: Bool = false

    var body: some View {
        Group {
            if let image {
                Image(uiImage: image)
                    .resizable()
                    .scaledToFill()
            } else if didFail {
                Color.gray.opacity(0.15)
            } else {
                ZStack {
                    Color.gray.opacity(0.08)
                    ProgressView()
                }
            }
        }
        .task(id: url) {
            await load()
        }
    }

    private func load() async {
        // Reset state when the URL changes.
        if image != nil || didFail {
            image = nil
            didFail = false
        }
        do {
            let (data, _) = try await NostrImageCache.session.data(from: url)
            if let decoded = UIImage(data: data) {
                image = decoded
            } else {
                didFail = true
            }
        } catch {
            didFail = true
        }
    }
}

/// View that resolves a URL through `NostrContentRenderer.imageLoader` so
/// components don't reference `AsyncImage` directly. Apps that install a
/// Kingfisher / Nuke loader on the renderer get every avatar / thumbnail /
/// media grid cell routed through it.
public struct NostrImageView: View {
    public var url: URL
    @Environment(\.nostrContentRenderer) private var renderer

    public init(url: URL) {
        self.url = url
    }

    public var body: some View {
        renderer.imageLoader(url)
    }
}

private struct NostrContentRendererKey: EnvironmentKey {
    static let defaultValue = NostrContentRenderer()
}

public extension EnvironmentValues {
    var nostrContentRenderer: NostrContentRenderer {
        get { self[NostrContentRendererKey.self] }
        set { self[NostrContentRendererKey.self] = newValue }
    }
}

public extension View {
    func nostrContentRenderer(_ renderer: NostrContentRenderer) -> some View {
        environment(\.nostrContentRenderer, renderer)
    }
}

import SwiftUI

/// Swift Codable mirror of the Rust `nmp_content::wire::ContentTreeWire`.
///
/// The Rust type is a flat *arena*: `nodes: [WireNode]` plus `roots: [UInt32]`.
/// Every recursive parent→child edge in the source tree is a `[UInt32]` of
/// indices into `nodes`. See `crates/nmp-content/src/wire/mod.rs` for the
/// canonical definition.
///
/// This file is shipped as a registry component so apps that install
/// `swiftui/content-core` get a complete, drift-resistant mirror without
/// hand-rolling Decodables.
public struct ContentTreeWire: Decodable, Equatable {
    public let nodes: [NostrWireNode]
    public let roots: [UInt32]
    public let mode: String?

    public init(nodes: [NostrWireNode], roots: [UInt32], mode: String? = nil) {
        self.nodes = nodes
        self.roots = roots
        self.mode = mode
    }

    /// Bounds-checked arena lookup.
    public func node(at index: UInt32) -> NostrWireNode? {
        let i = Int(index)
        guard i >= 0, i < nodes.count else { return nil }
        return nodes[i]
    }
}

/// Typed mirror of the Rust `nmp_content::MediaKind` enum. Raw values match the
/// PascalCase Rust serde representation (the Rust enum has no `rename_all`).
public enum NostrMediaKind: String, Decodable, Equatable {
    case image = "Image"
    case video = "Video"
    case audio = "Audio"
}

/// NIP-21 entity discriminator on the wire.
public enum NostrWireUriKind: String, Decodable, Equatable {
    case profile
    case event
    case address
}

/// Why a `placeholder` wire node was emitted.
public enum NostrWirePlaceholderReason: String, Decodable, Equatable {
    case depthLimit = "depth_limit"
    case unresolvedUri = "unresolved_uri"
}

/// Reserved payment segment (`WireNode::Invoice`).
public enum NostrWireInvoice: Decodable, Equatable {
    case bolt11(String)
    case bolt12(String)
    case cashu(String)

    private enum CodingKeys: String, CodingKey {
        case bolt11 = "Bolt11"
        case bolt12 = "Bolt12"
        case cashu = "Cashu"
    }

    public init(from decoder: Decoder) throws {
        let container = try decoder.container(keyedBy: CodingKeys.self)
        if let value = try container.decodeIfPresent(String.self, forKey: .bolt11) {
            self = .bolt11(value)
        } else if let value = try container.decodeIfPresent(String.self, forKey: .bolt12) {
            self = .bolt12(value)
        } else if let value = try container.decodeIfPresent(String.self, forKey: .cashu) {
            self = .cashu(value)
        } else {
            throw DecodingError.dataCorrupted(
                .init(codingPath: decoder.codingPath, debugDescription: "unknown invoice kind")
            )
        }
    }
}

/// Flattened, Codable projection of `nmp_core::nip21::NostrUri`. `uri` is the
/// round-trippable canonical `nostr:` URI; `primaryId` is the hex pubkey for
/// profiles, event id for events, or author pubkey for addresses.
public struct NostrWireUri: Decodable, Equatable {
    public let uri: String
    public let kind: NostrWireUriKind
    public let primaryId: String
    public let relays: [String]
    public let author: String?
    public let eventKind: UInt32?

    private enum CodingKeys: String, CodingKey {
        case uri, kind, relays, author
        case primaryId = "primary_id"
        case eventKind = "event_kind"
    }

    public init(
        uri: String,
        kind: NostrWireUriKind,
        primaryId: String,
        relays: [String] = [],
        author: String? = nil,
        eventKind: UInt32? = nil
    ) {
        self.uri = uri
        self.kind = kind
        self.primaryId = primaryId
        self.relays = relays
        self.author = author
        self.eventKind = eventKind
    }
}

/// One node in the `ContentTreeWire` arena. Covers every variant of the Rust
/// `WireNode` enum.
public enum NostrWireNode: Decodable, Equatable {
    case text(String)
    case mention(NostrWireUri)
    case eventRef(NostrWireUri)
    case hashtag(String)
    case url(String)
    case media(urls: [String], kind: NostrMediaKind)
    case emoji(shortcode: String, url: String?)
    case invoice(NostrWireInvoice)
    case heading(level: UInt8, children: [UInt32])
    case paragraph(children: [UInt32])
    case blockQuote(children: [UInt32])
    case codeBlock(info: String?, body: String)
    case list(orderedStart: UInt64?, items: [[UInt32]])
    case rule
    case emphasis(children: [UInt32])
    case strong(children: [UInt32])
    case inlineCode(String)
    case link(children: [UInt32], href: String?)
    case image(alt: String, title: String?, src: String?)
    case softBreak
    case hardBreak
    case placeholder(reason: NostrWirePlaceholderReason)

    private enum CodingKeys: String, CodingKey {
        case kind, text, uri, tag, url, urls
        case mediaKind = "media_kind"
        case shortcode, level, children, code, info, body, href
        case orderedStart = "ordered_start"
        case items, alt, title, src, reason, invoice
    }

    public init(from decoder: Decoder) throws {
        let container = try decoder.container(keyedBy: CodingKeys.self)
        let kind = try container.decode(String.self, forKey: .kind)
        switch kind {
        case "text":
            self = .text(try container.decode(String.self, forKey: .text))
        case "mention":
            self = .mention(try container.decode(NostrWireUri.self, forKey: .uri))
        case "event_ref":
            self = .eventRef(try container.decode(NostrWireUri.self, forKey: .uri))
        case "hashtag":
            self = .hashtag(try container.decode(String.self, forKey: .tag))
        case "url":
            self = .url(try container.decode(String.self, forKey: .url))
        case "media":
            self = .media(
                urls: try container.decode([String].self, forKey: .urls),
                kind: try container.decode(NostrMediaKind.self, forKey: .mediaKind)
            )
        case "emoji":
            self = .emoji(
                shortcode: try container.decode(String.self, forKey: .shortcode),
                url: try container.decodeIfPresent(String.self, forKey: .url)
            )
        case "invoice":
            self = .invoice(try container.decode(NostrWireInvoice.self, forKey: .invoice))
        case "heading":
            self = .heading(
                level: try container.decode(UInt8.self, forKey: .level),
                children: try container.decode([UInt32].self, forKey: .children)
            )
        case "paragraph":
            self = .paragraph(children: try container.decode([UInt32].self, forKey: .children))
        case "block_quote":
            self = .blockQuote(children: try container.decode([UInt32].self, forKey: .children))
        case "code_block":
            self = .codeBlock(
                info: try container.decodeIfPresent(String.self, forKey: .info),
                body: try container.decode(String.self, forKey: .body)
            )
        case "list":
            self = .list(
                orderedStart: try container.decodeIfPresent(UInt64.self, forKey: .orderedStart),
                items: try container.decode([[UInt32]].self, forKey: .items)
            )
        case "rule":
            self = .rule
        case "emphasis":
            self = .emphasis(children: try container.decode([UInt32].self, forKey: .children))
        case "strong":
            self = .strong(children: try container.decode([UInt32].self, forKey: .children))
        case "inline_code":
            self = .inlineCode(try container.decode(String.self, forKey: .code))
        case "link":
            self = .link(
                children: try container.decode([UInt32].self, forKey: .children),
                href: try container.decodeIfPresent(String.self, forKey: .href)
            )
        case "image":
            self = .image(
                alt: try container.decode(String.self, forKey: .alt),
                title: try container.decodeIfPresent(String.self, forKey: .title),
                src: try container.decodeIfPresent(String.self, forKey: .src)
            )
        case "soft_break":
            self = .softBreak
        case "hard_break":
            self = .hardBreak
        case "placeholder":
            self = .placeholder(
                reason: try container.decode(NostrWirePlaceholderReason.self, forKey: .reason)
            )
        default:
            // Forward-compat: any unknown kind collapses to a depth_limit
            // placeholder rather than failing the whole decode.
            self = .placeholder(reason: .depthLimit)
        }
    }
}

/// Deterministic identicon for a hex pubkey. Apps that don't supply an avatar
/// URL can render the geometric `identiconView(forPubkey:)` (a 5×5 symmetric
/// pixel grid in the GitHub-style — same input always produces the same
/// pattern). `color(forPubkey:)` is still exposed so apps can theme borders
/// or backgrounds with the same palette. Ported from Chirp's djb2-based
/// palette so installed apps stay visually consistent.
public enum NostrIdenticon {
    /// Returns a stable `Color` derived from a hex pubkey (or any string).
    /// Uses the djb2 hash mapped to HSL with fixed S/L for legibility.
    public static func color(forPubkey pubkey: String) -> Color {
        let hue = Double(djb2(pubkey) % 360) / 360.0
        return Color(hue: hue, saturation: 0.55, brightness: 0.75)
    }

    /// Single-character monogram derived from a hex pubkey (first char,
    /// uppercased). Retained for backward compatibility with v0.1 apps that
    /// still render a text initial overlay on top of `color(forPubkey:)`;
    /// new code should prefer `identiconView(forPubkey:)`.
    public static func initials(forPubkey pubkey: String) -> String {
        let trimmed = pubkey.trimmingCharacters(in: .whitespacesAndNewlines)
        if trimmed.isEmpty { return "?" }
        return String(trimmed.prefix(1)).uppercased()
    }

    /// 5×5 symmetric pixel-grid identicon, GitHub-style. Deterministic from
    /// the pubkey via djb2: the lower 15 bits of the hash decide which of
    /// the 15 left-half cells (3 columns × 5 rows) are filled; the right
    /// half is a horizontal mirror so the result is visually symmetric.
    ///
    /// The cell colour comes from `color(forPubkey:)`; empty cells use the
    /// same hue at 15% opacity so the overall tile reads as a tinted patch
    /// rather than blank.
    public static func identiconView(forPubkey pubkey: String, size: CGFloat = 40) -> some View {
        IdenticonGridView(pubkey: pubkey, size: size)
    }

    /// Returns the 5×5 symmetric fill pattern for a pubkey. Cell at
    /// `(row, col)` is filled iff `cells[row][col]` is true. Exposed for
    /// snapshot tests and apps that want to render the same pattern in a
    /// non-SwiftUI surface (e.g. `Canvas` exports).
    public static func cells(forPubkey pubkey: String) -> [[Bool]] {
        let hash = djb2(pubkey)
        var rows: [[Bool]] = []
        for row in 0..<5 {
            var line: [Bool] = Array(repeating: false, count: 5)
            for col in 0..<3 {
                let bit = row * 3 + col
                let filled = (hash >> UInt32(bit)) & 1 == 1
                line[col] = filled
                // Mirror columns 0 and 1 to columns 4 and 3 respectively;
                // column 2 is the centre and stays unchanged.
                if col < 2 {
                    line[4 - col] = filled
                }
            }
            rows.append(line)
        }
        return rows
    }

    private static func djb2(_ value: String) -> UInt32 {
        var hash: UInt32 = 5381
        for byte in value.utf8 {
            hash = (hash &* 33) &+ UInt32(byte)
        }
        return hash
    }
}

/// Internal renderer for `NostrIdenticon.identiconView`. Uses `Canvas` so the
/// whole identicon collapses to a single drawing pass — cheap enough to live
/// inside a `ForEach` row without measurable layout cost.
private struct IdenticonGridView: View {
    let pubkey: String
    let size: CGFloat

    var body: some View {
        let cells = NostrIdenticon.cells(forPubkey: pubkey)
        let color = NostrIdenticon.color(forPubkey: pubkey)
        return Canvas { context, canvasSize in
            let gridCount: CGFloat = 5
            // 1pt spacing between cells (visually crisp at any size ≥ 20pt).
            let spacing: CGFloat = 1
            let totalSpacing = spacing * (gridCount - 1)
            let cell = max(0, (min(canvasSize.width, canvasSize.height) - totalSpacing) / gridCount)
            for row in 0..<5 {
                for col in 0..<5 where cells[row][col] {
                    let x = CGFloat(col) * (cell + spacing)
                    let y = CGFloat(row) * (cell + spacing)
                    let rect = CGRect(x: x, y: y, width: cell, height: cell)
                    context.fill(Path(rect), with: .color(color))
                }
            }
        }
        .background(color.opacity(0.15))
        .frame(width: size, height: size)
    }
}

import SwiftUI

public struct NostrContentRun: Identifiable, Equatable {
    public enum Kind: Equatable {
        case text
        case mention(pubkey: String)
        case hashtag(String)
        case link(URL)
    }

    public var id: String
    public var label: String
    public var kind: Kind

    public init(id: String, label: String, kind: Kind) {
        self.id = id
        self.label = label
        self.kind = kind
    }
}

public struct NostrMinimalContentView: View {
    public var runs: [NostrContentRun]
    @Environment(\.nostrContentRenderer) private var renderer

    public init(runs: [NostrContentRun]) {
        self.runs = runs
    }

    public var body: some View {
        FlowLayout(spacing: 4) {
            ForEach(runs) { run in
                runView(run)
            }
        }
    }

    @ViewBuilder
    private func runView(_ run: NostrContentRun) -> some View {
        switch run.kind {
        case .text:
            Text(run.label)
                .foregroundStyle(renderer.textColor)
        case .mention(let pubkey):
            Button(run.label) {
                renderer.callbacks.onMentionTap(pubkey)
            }
            .buttonStyle(.plain)
            .foregroundStyle(renderer.mentionColor)
        case .hashtag(let tag):
            Button(run.label) {
                renderer.callbacks.onHashtagTap(tag)
            }
            .buttonStyle(.plain)
            .foregroundStyle(renderer.hashtagColor)
        case .link(let url):
            Button(run.label) {
                renderer.callbacks.onLinkTap(url)
            }
            .buttonStyle(.plain)
            .foregroundStyle(renderer.linkColor)
        }
    }
}

private struct FlowLayout: Layout {
    var spacing: CGFloat

    func sizeThatFits(
        proposal: ProposedViewSize,
        subviews: Subviews,
        cache: inout ()
    ) -> CGSize {
        layout(in: proposal.replacingUnspecifiedDimensions().width, subviews: subviews).size
    }

    func placeSubviews(
        in bounds: CGRect,
        proposal: ProposedViewSize,
        subviews: Subviews,
        cache: inout ()
    ) {
        let rows = layout(in: bounds.width, subviews: subviews).rows
        for row in rows {
            for item in row.items {
                subviews[item.index].place(
                    at: CGPoint(x: bounds.minX + item.origin.x, y: bounds.minY + item.origin.y),
                    proposal: ProposedViewSize(item.size)
                )
            }
        }
    }

    private func layout(in width: CGFloat, subviews: Subviews) -> FlowResult {
        var rows: [FlowRow] = []
        var current = FlowRow()
        var cursor = CGPoint.zero
        var rowHeight: CGFloat = 0

        for index in subviews.indices {
            let size = subviews[index].sizeThatFits(.unspecified)
            if cursor.x > 0, cursor.x + size.width > width {
                rows.append(current)
                cursor = CGPoint(x: 0, y: cursor.y + rowHeight + spacing)
                rowHeight = 0
                current = FlowRow()
            }

            current.items.append(FlowItem(index: index, origin: cursor, size: size))
            cursor.x += size.width + spacing
            rowHeight = max(rowHeight, size.height)
        }

        rows.append(current)
        let height = rows.last?.items.last.map { $0.origin.y + rowHeight } ?? 0
        return FlowResult(rows: rows, size: CGSize(width: width, height: height))
    }
}

private struct FlowResult {
    var rows: [FlowRow]
    var size: CGSize
}

private struct FlowRow {
    var items: [FlowItem] = []
}

private struct FlowItem {
    var index: Int
    var origin: CGPoint
    var size: CGSize
}

// MARK: - ContentTreeWire → [NostrContentRun] adapter

public extension ContentTreeWire {
    /// Flatten a `ContentTreeWire` into a list of `NostrContentRun` values
    /// suitable for `NostrMinimalContentView`. Walks the arena starting from
    /// `roots`, collapses inline-only structure (paragraph / heading /
    /// emphasis / strong / link / softBreak / hardBreak) into runs, and
    /// skips block-level nodes the minimal renderer doesn't support
    /// (`media`, `image`, `invoice`, `codeBlock`, `rule`, `eventRef`,
    /// `placeholder`, `list`, `blockQuote`).
    ///
    /// `softBreak` becomes a single space run; `hardBreak` becomes a
    /// `\n` text run so the `FlowLayout` can break visually. Emphasis /
    /// strong wrappers contribute only their children's text (no styling
    /// in the minimal view).
    func nostrMinimalRuns() -> [NostrContentRun] {
        var runs: [NostrContentRun] = []
        var counter = 0
        for index in roots {
            walkMinimal(index: index, runs: &runs, counter: &counter)
        }
        return runs
    }

    private func walkMinimal(
        index: UInt32,
        runs: inout [NostrContentRun],
        counter: inout Int
    ) {
        guard let node = node(at: index) else { return }
        switch node {
        case .text(let value):
            appendText(value, runs: &runs, counter: &counter)
        case .mention(let uri):
            let label = "@\(shortMentionLabel(uri))"
            append(label: label, kind: .mention(pubkey: uri.primaryId), runs: &runs, counter: &counter)
        case .hashtag(let tag):
            append(label: "#\(tag)", kind: .hashtag(tag), runs: &runs, counter: &counter)
        case .url(let value):
            if let url = URL(string: value) {
                append(label: value, kind: .link(url), runs: &runs, counter: &counter)
            } else {
                appendText(value, runs: &runs, counter: &counter)
            }
        case .link(let children, let href):
            // Fold the children into a single text label; if the href is a
            // valid URL emit one `.link` run with that label, otherwise emit
            // the children as plain text (preserves the visible label).
            let label = childrenText(children)
            if let href, !href.isEmpty, let url = URL(string: href) {
                append(label: label, kind: .link(url), runs: &runs, counter: &counter)
            } else if !label.isEmpty {
                appendText(label, runs: &runs, counter: &counter)
            }
        case .emoji(let shortcode, _):
            // Minimal view has no UIImage surface — fall back to literal
            // `:shortcode:` text so the run is still searchable / copyable.
            appendText(":\(shortcode):", runs: &runs, counter: &counter)
        case .emphasis(let children),
             .strong(let children),
             .paragraph(let children),
             .heading(_, let children):
            for child in children {
                walkMinimal(index: child, runs: &runs, counter: &counter)
            }
        case .softBreak:
            appendText(" ", runs: &runs, counter: &counter)
        case .hardBreak:
            appendText("\n", runs: &runs, counter: &counter)
        case .inlineCode(let value):
            appendText(value, runs: &runs, counter: &counter)
        case .image(let alt, _, _):
            // Block-level image — minimal view doesn't render images, but
            // surface the alt text so the run isn't silently dropped.
            if !alt.isEmpty {
                appendText("[\(alt)]", runs: &runs, counter: &counter)
            }
        case .eventRef,
             .invoice,
             .blockQuote,
             .codeBlock,
             .list,
             .rule,
             .media,
             .placeholder:
            // Block-level / non-inline nodes the minimal renderer doesn't
            // support. Apps wanting the full surface should use
            // `NostrContentView` instead.
            break
        }
    }

    private func childrenText(_ children: [UInt32]) -> String {
        var out = ""
        for index in children {
            collectText(index: index, into: &out)
        }
        return out
    }

    private func collectText(index: UInt32, into out: inout String) {
        guard let node = node(at: index) else { return }
        switch node {
        case .text(let value), .inlineCode(let value), .url(let value):
            out += value
        case .hashtag(let tag):
            out += "#\(tag)"
        case .emoji(let shortcode, _):
            out += ":\(shortcode):"
        case .mention(let uri):
            out += "@\(shortMentionLabel(uri))"
        case .emphasis(let children),
             .strong(let children),
             .paragraph(let children),
             .heading(_, let children),
             .link(let children, _):
            for child in children {
                collectText(index: child, into: &out)
            }
        case .softBreak:
            out += " "
        case .hardBreak:
            out += "\n"
        default:
            break
        }
    }

    private func appendText(_ value: String, runs: inout [NostrContentRun], counter: inout Int) {
        // Coalesce adjacent text runs so consumers don't see an artificial
        // run boundary between two `.text` segments emitted by the walker.
        if let last = runs.last, last.kind == .text {
            var merged = last
            merged.label += value
            runs[runs.count - 1] = merged
            return
        }
        append(label: value, kind: .text, runs: &runs, counter: &counter)
    }

    private func append(
        label: String,
        kind: NostrContentRun.Kind,
        runs: inout [NostrContentRun],
        counter: inout Int
    ) {
        runs.append(NostrContentRun(id: "run-\(counter)", label: label, kind: kind))
        counter += 1
    }

    /// Inline short mention label so this extension doesn't need to pull in
    /// `content-view`. Mirrors `NostrContentView.defaultMentionLabel`: shows
    /// the full pubkey when ≤12 chars, otherwise `prefix(8)…suffix(4)`.
    private func shortMentionLabel(_ uri: NostrWireUri) -> String {
        let value = uri.primaryId
        guard value.count > 12 else { return value }
        return "\(value.prefix(8))…\(value.suffix(4))"
    }
}

