import androidx.compose.ui.Alignment
import androidx.compose.ui.Modifier
import androidx.compose.ui.draw.clip
import androidx.compose.ui.graphics.Color
import androidx.compose.ui.semantics.clearAndSetSemantics
import androidx.compose.ui.text.font.FontWeight
import androidx.compose.ui.unit.Dp
import androidx.compose.ui.unit.dp
import androidx.compose.ui.unit.sp
import coil.compose.SubcomposeAsyncImage

/**
 * Circular avatar for a Nostr profile. Shows the remote picture when
 * available; falls back to a deterministic identicon derived from `pubkey`.
 *
 * Replace [SubcomposeAsyncImage] with Glide/Picasso/custom if you already
 * have an image loader — the identicon fallback is self-contained.
 *
 * Depends on `compose/user-avatar` for [ProfileWire].
 */
@Composable
fun NostrAvatar(
    pubkey: String,
    avatarUrl: String? = null,
    size: Dp = 40.dp,
    modifier: Modifier = Modifier,
) {
    val baseModifier = modifier
        .size(size)
        .clip(CircleShape)
        .clearAndSetSemantics {}

    if (!avatarUrl.isNullOrEmpty()) {
        SubcomposeAsyncImage(
            model = avatarUrl,
            contentDescription = null,
            modifier = baseModifier,
            error = { NostrIdenticonBox(pubkey = pubkey, size = size) },
            loading = { NostrIdenticonBox(pubkey = pubkey, size = size) },
        )
    } else {
        NostrIdenticonBox(pubkey = pubkey, size = size, modifier = baseModifier)
    }
}

/** Convenience overload accepting a [ProfileWire]. */
@Composable
fun NostrAvatar(
    profile: ProfileWire,
    size: Dp = 40.dp,
    modifier: Modifier = Modifier,
) = NostrAvatar(
    pubkey = profile.pubkey,
    avatarUrl = profile.avatarUrl,
    size = size,
    modifier = modifier,
)

// ── Identicon ────────────────────────────────────────────────────────────────

private val IDENTICON_PALETTE = listOf(
    Color(0xFF5C33CF),
    Color(0xFF1A87D1),
    Color(0xFF218C6A),
    Color(0xFFD1542E),
    Color(0xFFC12573),
    Color(0xFF333333),
)

private fun identiconColor(pubkey: String): Color {
    val sum = pubkey.take(4).sumOf { it.code }
    return IDENTICON_PALETTE[sum % IDENTICON_PALETTE.size]
}

private fun identiconInitials(pubkey: String): String =
    pubkey.take(2).uppercase()

@Composable
private fun NostrIdenticonBox(pubkey: String, size: Dp, modifier: Modifier = Modifier) {
    Box(
        contentAlignment = Alignment.Center,
        modifier = modifier
            .size(size)
            .clip(CircleShape)
            .background(identiconColor(pubkey)),
    ) {
        Text(
            text = identiconInitials(pubkey),
            color = Color.White,
            fontSize = (size.value * 0.35f).sp,
            fontWeight = FontWeight.SemiBold,
        )
    }
}

package org.nmp.registry

import androidx.compose.foundation.clickable
import androidx.compose.foundation.layout.Column
import androidx.compose.foundation.layout.Row
import androidx.compose.foundation.layout.Spacer
import androidx.compose.foundation.layout.width
import androidx.compose.runtime.Composable
import androidx.compose.ui.Alignment
import androidx.compose.ui.Modifier
import androidx.compose.ui.semantics.contentDescription
import androidx.compose.ui.semantics.semantics
import androidx.compose.ui.unit.Dp
import androidx.compose.ui.unit.dp

/**
 * Compact author header: avatar, display name, and optional NIP-05 badge.
 *
 * The most common pattern in note feeds and thread views. Tap routes
 * through [onTap] so this component can be used in any navigation stack.
 *
 * Depends on `compose/user-avatar`, `compose/user-name`, `compose/user-nip05`.
 */
@Composable
fun NostrUserCard(
    profile: ProfileWire,
    avatarSize: Dp = 40.dp,
    onTap: ((String) -> Unit)? = null,
    modifier: Modifier = Modifier,
) {
    val tapModifier = if (onTap != null) {
        modifier.clickable { onTap(profile.pubkey) }
    } else {
        modifier
    }

    Row(
        verticalAlignment = Alignment.CenterVertically,
        modifier = tapModifier.semantics(mergeDescendants = true) {
            contentDescription = "${profile.display}, profile"
        },
    ) {
        NostrAvatar(profile = profile, size = avatarSize)
        Spacer(Modifier.width(10.dp))
        Column {
            NostrProfileName(profile = profile)
            NostrNip05Badge(profile = profile)
        }
    }
}
